namespace NotificationsApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly object _lock = new();

    public NotificationService()
    {
        // Seed initial notifications
        _notifications.AddRange(new[]
        {
            new Notification { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new Notification { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new Notification { Id = _nextId++, Message = "New feature available: Dark Mode.", Timestamp = DateTime.UtcNow.AddMinutes(-2) },
        });
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given timestamp.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        lock (_lock)
        {
            var newer = _notifications.Where(n => n.Timestamp > since).ToList();
            return Task.FromResult(newer);
        }
    }

    /// <summary>Simulates new notifications arriving over time.</summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Server maintenance scheduled.",
            "Your export is ready to download.",
            "A comment was added to your thread.",
        };

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new Notification
            {
                Id = _nextId++,
                Message = msg,
                Timestamp = DateTime.UtcNow
            });
        }
    }
}

