@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<span class="badge bg-primary fs-5 mb-3 d-inline-block">
    @_notifications.Count notification@(_notifications.Count == 1 ? "" : "s")
</span>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private DateTime _lastCheck;

    // Runs during SSR *and* on interactive re-init — but data is only fetched
    // once because the component state survives the SSR→interactive transition.
    protected override async Task OnInitializedAsync()
    {
        _notifications = await NotificationSvc.GetNotificationsAsync();
        _lastCheck = _notifications.Count > 0
            ? _notifications.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    // Only fires once the page is live and interactive in the browser.
    // This is where we start the polling loop.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                // Simulate new notifications arriving server-side
                NotificationSvc.SimulateIncoming();

                var newer = await NotificationSvc.GetNotificationsSinceAsync(_lastCheck);
                if (newer.Count > 0)
                {
                    _notifications.AddRange(newer);
                    _lastCheck = newer.Max(n => n.Timestamp);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                // Expected on dispose — exit cleanly
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

